text:
&-body-cell {
  border-top: @calendar-border-size solid @calendar-body-cell-border-color;
  padding: @calendar-body-cell-padding;
  height: @calendar-body-cell-height;
  line-height: @calendar-body-line-height;
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  justify-content: flex-start;
  margin-left: @calendar-body-cell-margin-left;
  transition-duration: @calendar-transition-duration;
  transition-property: @calendar-transition-property;
  transition-timing-function: @calendar-transition-timing-function;

  &-content {
    padding: @calendar-body-cell-content-padding;
    width: 100%;
    box-sizing: border-box;
  }

  &.@{prefix}-is-checked {
    background-color: @calendar-body-cell-check-bg-color;

    &:hover {
      background-color: @calendar-body-cell-check-bg-color;
    }
  }

  &--now {
    border-top: @calendar-border-size solid @calendar-highlight-color;
    .@{prefix}-calendar__table-body-cell-display {
      color: @calendar-body-cell-display-now-color;
    }
  }
}

body .ui-calendar {
    position: relative;

    button.ui-datepicker-trigger {
        height: 32px;
        top: -12px;
        .box-shadow(none);
        border: none;
        overflow: visible;
        background: transparent;
        position: absolute;
        right: -2px;
        width: 2.4em;

        > span.ui-icon-calendar {
            background: none !important;
            position: relative !important;
            top: 0 !important;
            display: inline;
            overflow: hidden;

            &:before {
                font-family: FontAwesome;
                color: @admin-text-color;
                position: relative;
                top: 0;
                font-size: 20px;
                overflow: hidden;
                content: "\f073" !important;
            }

            &.icon-ripple {
                left: 1px;
            }
        }

        .ui-button {
            background: @light-blue;
        }

    }
}

> li {
  float: left;
  // Make the list-items overlay the bottom border
  margin-bottom: -1px;

  // Actual tabs (as links)
  > a {
    //margin-right: 2px;
    line-height: @line-height-base;
    // border: 1px solid transparent;
    // border-radius: @border-radius-base @border-radius-base 0 0;
    border-bottom: 1px solid transparent;
    &:hover {
      //border-color: @nav-tabs-link-hover-border-color @nav-tabs-link-hover-border-color @nav-tabs-border-color;
      border-color: @nav-tabs-border-color;
    }
  }

  &.@{prefix-cls-nav}-disabled > a {
    color: @nav-disabled-link-color;

    &:hover,
    &:focus {
      color: @nav-disabled-link-hover-color;
      text-decoration: none;
      background-color: transparent;
      cursor: @cursor-disabled;
      border-bottom: 1px solid @nav-disabled-link-base-hover-border-color;
    }
  }

  // Active state, and its :hover to override normal :hover
  &.@{prefix-cls-nav}-active > a {
    &,
    &:hover,
    &:focus {
      color: @nav-tabs-active-link-hover-color;
      background-color: @nav-tabs-active-link-hover-bg;
      //border: 1px solid @nav-tabs-active-link-hover-border-color;
      border-bottom: 1px solid @nav-tabs-active-link-hover-color;
      //border-bottom-color: transparent;
      cursor: default;
    }
  }


}

atom-text-editor {
    background-color: @syntax-background-color;
    color: @syntax-text-color;

    .wrap-guide {
        background-color: @syntax-wrap-guide-color;
    }

    .indent-guide {
        color: @syntax-indent-guide-color;
    }

    .invisible-character {
        color: @syntax-invisible-character-color;
    }

    .gutter {
        background-color: @syntax-gutter-background-color;
        color: @syntax-gutter-text-color;

        .line-number {
            &.cursor-line {
                background-color: @syntax-gutter-background-color-selected;
                color: @syntax-gutter-text-color-selected;
            }

            &.cursor-line-no-selection {
                color: @syntax-gutter-text-color-selected;
            }
        }
    }

    .fold-marker:after,
    .gutter .line-number.folded,
    .gutter .line-number:after {
        color: @light-gray;
    }

    .invisible {
        color: @syntax-text-color;
    }

    .cursor {
        color: @syntax-cursor-color;
    }

    .selection .region {
        background-color: @syntax-selection-color;
    }
}

&-body {
  display: flex;
  flex-direction: column;
  justify-self: center;
  align-items: center;
  flex: 1;

  &-cell {
    justify-content: center;
    align-items: center;

    &:hover {
      background-color: @calendar-bg;
    }

    &-display {
      font: @calendar-card-body-cell-display-font;
      padding-top: @calendar-card-body-cell-display-padding;
      padding-bottom: @calendar-card-body-cell-display-padding;
      text-align: center;
      border-radius: @calendar-card-body-cell-display-border-radius;
      transition: all @calendar-transition-duration @calendar-transition-timing-function;

      &:hover {
        box-shadow: inset 0 0 0 1px @calendar-highlight-color;
        transition: box-shadow @calendar-transition-duration @calendar-transition-timing-function;
      }
    }

    &--now {
      .@{prefix}-calendar__table-body-cell-display {
        color: @calendar-highlight-color;
        background-color: @calendar-body-cell-check-bg-color;
        position: relative;
      }
    }
  }
}

@media only screen and (max-width : @largestMobileScreen) {

  .ui.stackable.grid .ui.vertical.divider,
  .ui.grid .stackable.row .ui.vertical.divider {
    display: table;
    white-space: nowrap;
    height: auto;
    margin: @horizontalMargin;
    overflow: hidden;
    line-height: 1;
    text-align: center;
    position: static;
    top: 0;
    left: 0;
    transform: none;
  }

  .ui.stackable.grid .ui.vertical.divider:before,
  .ui.grid .stackable.row .ui.vertical.divider:before,
  .ui.stackable.grid .ui.vertical.divider:after,
  .ui.grid .stackable.row .ui.vertical.divider:after {
    position: static;
    left: 0;
    border-left: none;
    border-right: none;
    content: '';
    display: table-cell;
    position: relative;
    top: 50%;
    width: 50%;
    background-repeat: no-repeat;
  }

  .ui.stackable.grid .ui.vertical.divider:before,
  .ui.grid .stackable.row .ui.vertical.divider:before {
    background-position: right @horizontalDividerMargin top 50%;
  }
  .ui.stackable.grid .ui.vertical.divider:after,
  .ui.grid .stackable.row .ui.vertical.divider:after {
    background-position: left @horizontalDividerMargin top 50%;
  }
}

@media only screen and (max-width: 767.98px) {
  .ui.stackable.menu {
    -webkit-box-orient: vertical;
    -webkit-box-direction: normal;
        -ms-flex-direction: column;
            flex-direction: column;
  }
  .ui.stackable.menu.pointing .active.item::after {
    display: none;
  }
  .ui.stackable.menu .item {
    width: 100% !important;
  }
  .ui.stackable.menu .item::before {
    position: absolute;
    content: '';
    top: auto;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 1px;
    background: rgba(34, 36, 38, 0.1);
  }
  .ui.stackable.menu .left.menu,
  .ui.stackable.menu .left.item {
    margin-right: 0 !important;
  }
  .ui.stackable.menu .right.menu,
  .ui.stackable.menu .right.item {
    margin-left: 0 !important;
  }
  .ui.stackable.menu .center.menu,
  .ui.stackable.menu .center.item {
    margin-left: 0 !important;
    margin-right: 0 !important;
  }
  .ui.stackable.menu .right.menu,
  .ui.stackable.menu .center.menu,
  .ui.stackable.menu .left.menu {
    -webkit-box-orient: vertical;
    -webkit-box-direction: normal;
        -ms-flex-direction: column;
            flex-direction: column;
  }
}
